import React, { useState, useEffect } from 'react';
import { adminAPI, productsAPI } from '../../api';
import styles from './AdminPage.module.css';

const EMPTY_PRODUCT = {
  name: '', description: '', price: '', image_url: '',
  category: 'fruits', stock: 0,
  is_new: false, is_popular: false, is_day_item: false, is_discount: false,
};

const EMPTY_MODAL = {
  trigger_category: 'fruits', title: '', description: '',
  product_id: '', is_active: true,
};

export default function AdminPage() {
  const [tab, setTab]             = useState('products');
  const [products, setProducts]   = useState([]);
  const [adModals, setAdModals]   = useState([]);
  const [loading, setLoading]     = useState(true);

  // Форма товара
  const [form, setForm]       = useState(EMPTY_PRODUCT);
  const [editId, setEditId]   = useState(null);
  const [formMsg, setFormMsg] = useState('');

  // Форма попапа
  const [modalForm, setModalForm] = useState(EMPTY_MODAL);
  const [modalMsg, setModalMsg]   = useState('');

  useEffect(() => {
    loadAll();
  }, []);

  const loadAll = async () => {
    setLoading(true);
    try {
      const [{ data: prods }, { data: modals }] = await Promise.all([
        productsAPI.getAll({ limit: 100 }),
        adminAPI.getAdModals(),
      ]);
      setProducts(prods.products || []);
      setAdModals(modals || []);
    } catch {/* ignore */}
    finally { setLoading(false); }
  };

  // ── Товары ────────────────────────────────────────────────
  const handleFormChange = (e) => {
    const { name, value, type, checked } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    setFormMsg('');
    const payload = { ...form, price: parseFloat(form.price), stock: parseInt(form.stock, 10) };

    try {
      if (editId) {
        await adminAPI.updateProduct(editId, payload);
        setFormMsg('✓ Товар обновлён');
      } else {
        await adminAPI.createProduct(payload);
        setFormMsg('✓ Товар добавлен');
      }
      setForm(EMPTY_PRODUCT);
      setEditId(null);
      loadAll();
    } catch (err) {
      setFormMsg('Ошибка: ' + (err.response?.data?.error || 'попробуйте снова'));
    }
    setTimeout(() => setFormMsg(''), 3000);
  };

  const handleEdit = (product) => {
    setForm({
      name:        product.name,
      description: product.description,
      price:       product.price,
      image_url:   product.image_url,
      category:    product.category,
      stock:       product.stock,
      is_new:      product.is_new,
      is_popular:  product.is_popular,
      is_day_item: product.is_day_item,
      is_discount: product.is_discount,
    });
    setEditId(product.id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Удалить товар?')) return;
    try {
      await adminAPI.deleteProduct(id);
      loadAll();
    } catch {/* ignore */}
  };

  // ── Попапы ────────────────────────────────────────────────
  const handleModalChange = (e) => {
    const { name, value, type, checked } = e.target;
    setModalForm((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleModalSubmit = async (e) => {
    e.preventDefault();
    try {
      await adminAPI.createAdModal(modalForm);
      setModalMsg('✓ Попап сохранён');
      setModalForm(EMPTY_MODAL);
      loadAll();
    } catch (err) {
      setModalMsg('Ошибка: ' + (err.response?.data?.error || 'попробуйте снова'));
    }
    setTimeout(() => setModalMsg(''), 3000);
  };

  if (loading) {
    return (
      <div className={styles.loadingWrap}>
        <div className={styles.spinner} />
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className="container">
        {/* Шапка */}
        <div className={styles.adminHeader}>
          <div>
            <h1 className={styles.adminTitle}>👑 Админ-панель</h1>
            <p className={styles.adminSub}>Управление контентом Фрукт Край</p>
          </div>
          <div className={styles.stats}>
            <div className={styles.statCard}>
              <span className={styles.statNum}>{products.length}</span>
              <span className={styles.statLabel}>Товаров</span>
            </div>
            <div className={styles.statCard}>
              <span className={styles.statNum}>{adModals.length}</span>
              <span className={styles.statLabel}>Попапов</span>
            </div>
          </div>
        </div>

        {/* Вкладки */}
        <div className={styles.tabs}>
          {[
            { key: 'products', label: '🛍️ Товары' },
            { key: 'modals',   label: '🎁 Реклама' },
          ].map((t) => (
            <button
              key={t.key}
              className={`${styles.tab} ${tab === t.key ? styles.activeTab : ''}`}
              onClick={() => setTab(t.key)}
            >
              {t.label}
            </button>
          ))}
        </div>

        {/* ── Товары ─────────────────────────────────────── */}
        {tab === 'products' && (
          <div className={styles.tabContent}>
            {/* Форма */}
            <div className={styles.formCard}>
              <h2 className={styles.formTitle}>
                {editId ? '✏️ Редактировать товар' : '➕ Добавить товар'}
              </h2>

              <form className={styles.productForm} onSubmit={handleProductSubmit}>
                <div className={styles.formGrid}>
                  <div className={styles.field}>
                    <label className={styles.label}>Название *</label>
                    <input
                      name="name" required
                      className={styles.input}
                      value={form.name}
                      onChange={handleFormChange}
                      placeholder="Название товара"
                    />
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Цена (₽) *</label>
                    <input
                      name="price" type="number" required min="0" step="0.01"
                      className={styles.input}
                      value={form.price}
                      onChange={handleFormChange}
                      placeholder="0.00"
                    />
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Категория *</label>
                    <select
                      name="category"
                      className={styles.input}
                      value={form.category}
                      onChange={handleFormChange}
                    >
                      <option value="vegetables">🥕 Овощи</option>
                      <option value="fruits">🍎 Фрукты</option>
                      <option value="desserts">🍰 Десерты</option>
                    </select>
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>Остаток (шт.)</label>
                    <input
                      name="stock" type="number" min="0"
                      className={styles.input}
                      value={form.stock}
                      onChange={handleFormChange}
                    />
                  </div>
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Описание</label>
                  <textarea
                    name="description"
                    className={`${styles.input} ${styles.textarea}`}
                    value={form.description}
                    onChange={handleFormChange}
                    placeholder="Краткое описание товара"
                  />
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>URL изображения</label>
                  <input
                    name="image_url"
                    className={styles.input}
                    value={form.image_url}
                    onChange={handleFormChange}
                    placeholder="https://example.com/image.jpg"
                  />
                </div>

                {/* Флаги */}
                <div className={styles.flags}>
                  {[
                    { name: 'is_new',      label: '✨ Новинка' },
                    { name: 'is_popular',  label: '🔥 Популярный' },
                    { name: 'is_day_item', label: '⭐ Товар дня' },
                    { name: 'is_discount', label: '💰 Скидка' },
                  ].map((flag) => (
                    <label key={flag.name} className={styles.checkboxLabel}>
                      <input
                        type="checkbox"
                        name={flag.name}
                        checked={form[flag.name]}
                        onChange={handleFormChange}
                        className={styles.checkbox}
                      />
                      {flag.label}
                    </label>
                  ))}
                </div>

                {formMsg && (
                  <p className={`${styles.msg} ${formMsg.startsWith('Ошибка') ? styles.msgError : styles.msgOk}`}>
                    {formMsg}
                  </p>
                )}

                <div className={styles.formActions}>
                  <button type="submit" className="btn btn-cherry">
                    {editId ? 'Сохранить изменения' : 'Добавить товар'}
                  </button>
                  {editId && (
                    <button
                      type="button"
                      className="btn btn-ghost"
                      onClick={() => { setEditId(null); setForm(EMPTY_PRODUCT); }}
                    >
                      Отмена
                    </button>
                  )}
                </div>
              </form>
            </div>

            {/* Таблица товаров */}
            <div className={styles.tableWrap}>
              <h2 className={styles.tableTitle}>Все товары ({products.length})</h2>
              <div className={styles.table}>
                <div className={styles.tableHead}>
                  <span>Название</span>
                  <span>Категория</span>
                  <span>Цена</span>
                  <span>Остаток</span>
                  <span>Флаги</span>
                  <span>Действия</span>
                </div>
                {products.map((p) => (
                  <div key={p.id} className={styles.tableRow}>
                    <span className={styles.productName}>{p.name}</span>
                    <span className={styles.catCell}>
                      {p.category === 'vegetables' ? '🥕' :
                       p.category === 'fruits'     ? '🍎' : '🍰'}
                      {' '}{p.category}
                    </span>
                    <span className={styles.priceCell}>
                      {p.price.toLocaleString('ru-RU')} ₽
                    </span>
                    <span className={styles.stockCell}>
                      <span className={p.stock <= 5 ? styles.lowStock : ''}>
                        {p.stock}
                      </span>
                    </span>
                    <span className={styles.flagsCell}>
                      {p.is_new      && <span className="badge badge-new">New</span>}
                      {p.is_popular  && <span className="badge badge-popular">Hot</span>}
                      {p.is_day_item && <span className="badge badge-day">Day</span>}
                    </span>
                    <span className={styles.actionsCell}>
                      <button
                        className={`btn btn-outline btn-sm ${styles.editBtn}`}
                        onClick={() => handleEdit(p)}
                      >
                        Изменить
                      </button>
                      <button
                        className={`${styles.deleteBtn}`}
                        onClick={() => handleDelete(p.id)}
                      >
                        🗑️
                      </button>
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* ── Реклама ────────────────────────────────────── */}
        {tab === 'modals' && (
          <div className={styles.tabContent}>
            <div className={styles.formCard}>
              <h2 className={styles.formTitle}>➕ Создать рекламный попап</h2>

              <form className={styles.productForm} onSubmit={handleModalSubmit}>
                <div className={styles.formGrid}>
                  <div className={styles.field}>
                    <label className={styles.label}>Триггер-категория</label>
                    <select
                      name="trigger_category"
                      className={styles.input}
                      value={modalForm.trigger_category}
                      onChange={handleModalChange}
                    >
                      <option value="vegetables">🥕 Овощи</option>
                      <option value="fruits">🍎 Фрукты</option>
                      <option value="desserts">🍰 Десерты</option>
                    </select>
                  </div>

                  <div className={styles.field}>
                    <label className={styles.label}>ID товара для предложения</label>
                    <select
                      name="product_id"
                      className={styles.input}
                      value={modalForm.product_id}
                      onChange={handleModalChange}
                      required
                    >
                      <option value="">— Выберите товар —</option>
                      {products.map((p) => (
                        <option key={p.id} value={p.id}>
                          {p.name} ({p.price} ₽)
                        </option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Заголовок попапа</label>
                  <input
                    name="title" required
                    className={styles.input}
                    value={modalForm.title}
                    onChange={handleModalChange}
                    placeholder="Попробуйте к этому..."
                  />
                </div>

                <div className={styles.field}>
                  <label className={styles.label}>Описание</label>
                  <textarea
                    name="description"
                    className={`${styles.input} ${styles.textarea}`}
                    value={modalForm.description}
                    onChange={handleModalChange}
                    placeholder="Отличное дополнение к вашей покупке!"
                  />
                </div>

                <label className={styles.checkboxLabel}>
                  <input
                    type="checkbox"
                    name="is_active"
                    checked={modalForm.is_active}
                    onChange={handleModalChange}
                    className={styles.checkbox}
                  />
                  Активен
                </label>

                {modalMsg && (
                  <p className={`${styles.msg} ${modalMsg.startsWith('Ошибка') ? styles.msgError : styles.msgOk}`}>
                    {modalMsg}
                  </p>
                )}

                <button type="submit" className="btn btn-cherry">
                  Создать попап
                </button>
              </form>
            </div>

            {/* Список попапов */}
            <div className={styles.modalsList}>
              <h2 className={styles.tableTitle}>Все попапы ({adModals.length})</h2>
              {adModals.map((m) => (
                <div key={m.id} className={styles.modalCard}>
                  <div className={styles.modalCardLeft}>
                    <p className={styles.modalCardTitle}>{m.title}</p>
                    <p className={styles.modalCardDesc}>{m.description}</p>
                  </div>
                  <div className={styles.modalCardRight}>
                    <span className={`${styles.statusPill} ${m.is_active ? styles.active : styles.inactive}`}>
                      {m.is_active ? 'Активен' : 'Выключен'}
                    </span>
                    <span className={styles.modalCat}>
                      {m.trigger_category}
                    </span>
                  </div>
                </div>
              ))}
              {adModals.length === 0 && (
                <p className={styles.emptyText}>Попапов пока нет</p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
